// NeonGridBackground.jsx
export default function NeonGridBackground({ children, className = '' }) {
  return (
    <div className={`relative overflow-hidden bg-[#030712] ${className}`}>
      {/* Grid lines */}
      <div
        className="absolute inset-0"
        style={{
          backgroundImage:
            'linear-gradient(rgba(0,229,255,0.07) 1px, transparent 1px), linear-gradient(90deg, rgba(0,229,255,0.07) 1px, transparent 1px)',
          backgroundSize: '24px 24px',
        }}
      />
      {/* Radial glow */}
      <div className="absolute inset-0 bg-[radial-gradient(circle_at_50%_120%,rgba(0,229,255,0.28),transparent_60%)]" />
      <div className="relative z-10">{children}</div>
    </div>
  );
}

// RollingWindowBackground.jsx
// Add to your global CSS:
// @keyframes rollX { 0% { transform: translateX(-120%); } 100% { transform: translateX(120%); } }

export default function RollingWindowBackground({ children, className = '' }) {
  return (
    <div className={`relative overflow-hidden bg-[#050b1a] ${className}`}>
      {/* Sweeping bar */}
      <div
        className="absolute inset-0"
        style={{
          background: 'linear-gradient(90deg, transparent 0%, rgba(0,229,255,0.28) 35%, transparent 70%)',
          animation: 'rollX 5s linear infinite',
        }}
      />
      {/* Depth radial */}
      <div className="absolute inset-0 bg-[radial-gradient(circle_at_70%_30%,rgba(14,165,233,0.25),transparent_40%)]" />
      <div className="relative z-10">{children}</div>
    </div>
  );
}

// TerminalHeader.jsx
export default function TerminalHeader({ brand = 'SYS.NAV', links = [], cta = 'Launch' }) {
  return (
    <header className="w-full border-b border-cyan-900/60 bg-black/80 backdrop-blur-md">
      <div className="mx-auto flex max-w-7xl items-center justify-between px-6 py-3">
        <div className="flex items-center gap-3">
          <div className="h-2 w-2 animate-pulse rounded-full bg-cyan-400" />
          <span className="font-mono text-sm font-bold tracking-[0.25em] text-cyan-300">
            {brand}
          </span>
        </div>
        <nav className="hidden items-center gap-6 md:flex">
          {links.map((link) => (
            <a
              key={link.label}
              href={link.href}
              className="font-mono text-xs uppercase tracking-[0.2em] text-cyan-600 transition hover:text-cyan-300"
            >
              {link.label}
            </a>
          ))}
        </nav>
        <button className="border border-cyan-600 px-4 py-1.5 font-mono text-xs uppercase tracking-[0.2em] text-cyan-300 transition hover:bg-cyan-400 hover:text-black">
          {cta}
        </button>
      </div>
    </header>
  );
}

// GlassNeonHeader.jsx
export default function GlassNeonHeader({ brand = 'BRAND', links = [], cta = 'Sign Up' }) {
  return (
    <header className="relative z-10 px-4 pt-4">
      <div className="mx-auto flex max-w-7xl items-center justify-between rounded-xl border border-cyan-500/30 bg-black/50 px-5 py-3 shadow-[0_0_30px_rgba(0,229,255,0.06)] backdrop-blur-xl">
        <span className="text-sm font-semibold uppercase tracking-[0.25em] text-cyan-200">
          {brand}
        </span>
        <nav className="hidden items-center gap-8 md:flex">
          {links.map((link) => (
            <a
              key={link.label}
              href={link.href}
              className="text-xs uppercase tracking-[0.2em] text-cyan-400/80 transition hover:text-cyan-200"
            >
              {link.label}
            </a>
          ))}
        </nav>
        <button className="rounded-lg border border-cyan-400/50 bg-cyan-400/10 px-4 py-1.5 text-xs uppercase tracking-[0.18em] text-cyan-300 transition hover:bg-cyan-400 hover:text-black">
          {cta}
        </button>
      </div>
    </header>
  );
}

// TypeGlowText.jsx
// Add to global CSS:
// @keyframes typing { 0% { width: 0; } 40%, 80% { width: 22ch; } 100% { width: 0; } }
// @keyframes blink { 0%,49% { border-color: rgba(34,211,238,1); } 50%,100% { border-color: transparent; } }

export default function TypeGlowText({ text = 'Deploying Neon Interface', className = '' }) {
  return (
    <p
      className={`overflow-hidden whitespace-nowrap border-r-2 border-cyan-400 font-mono text-sm font-semibold uppercase tracking-[0.2em] text-cyan-300 ${className}`}
      style={{
        width: 0,
        animation: 'typing 3s steps(22, end) infinite, blink 0.8s step-end infinite',
      }}
    >
      {text}
    </p>
  );
}

// ScanlineSweep.jsx
// Add to global CSS:
// @keyframes scanY { 0% { transform: translateY(-130%); } 100% { transform: translateY(130%); } }

export default function ScanlineSweep({ children, className = '' }) {
  return (
    <div className={`relative overflow-hidden ${className}`}>
      {/* Scan bar */}
      <div
        className="pointer-events-none absolute inset-0 z-20"
        style={{
          background: 'linear-gradient(180deg, transparent 0%, rgba(0,229,255,0.18) 50%, transparent 100%)',
          animation: 'scanY 2.6s linear infinite',
        }}
      />
      {/* Scanlines overlay */}
      <div
        className="pointer-events-none absolute inset-0 z-10 opacity-40"
        style={{
          backgroundImage: 'repeating-linear-gradient(0deg, transparent 0, transparent 3px, rgba(255,255,255,0.07) 4px)',
        }}
      />
      <div className="relative z-0">{children}</div>
    </div>
  );
}

// HologramTitle.jsx
export default function HologramTitle({ children, as: Tag = 'h1', className = '' }) {
  return (
    <Tag
      className={`font-black uppercase tracking-[0.18em] text-cyan-300 ${className}`}
      style={{
        textShadow:
          '0 0 12px rgba(0,229,255,0.7), 0 0 40px rgba(0,229,255,0.3), 2px 2px 0 rgba(0,180,220,0.4)',
      }}
    >
      {children}
    </Tag>
  );
}

// FlickerCaption.jsx
// Add to global CSS:
// @keyframes flicker { 0%,17%,19%,22%,63%,65%,100% { opacity: 1; } 18%,21%,64% { opacity: 0.35; } }

export default function FlickerCaption({ children, className = '' }) {
  return (
    <p
      className={`font-mono text-xs uppercase tracking-[0.15em] text-cyan-500 ${className}`}
      style={{ animation: 'flicker 2.4s linear infinite' }}
    >
      {children}
    </p>
  );
}
